const token = $input.first().json.headers['x-wati-token'];
if (!token || token !== 'CrackTesos2026_WH_Token') {
  return [{json: {ok: 'false', encontrado: 'false', mensaje: 'No autorizado'}}];
}
const body = $input.first().json.body;
let phone = (body.phone || '').toString().replace(/[^0-9]/g, '');
if (!phone.startsWith('57') && phone.length === 10) phone = '57' + phone;
if (!phone || phone.length < 10) {
  return [{json: {ok: 'false', encontrado: 'false', mensaje: 'Teléfono inválido'}}];
}
return [{json: {ok: 'true', phone}}];

const phone = $('Validar').first().json.phone;
const rows = $input.all();
if (!rows.length || !rows[0].json.user_id) {
  return [{json: {ok: 'true', encontrado: 'false', phone, mensaje: 'Usuario no encontrado en la base'}}];
}
const u = rows[0].json;
return [{json: {
  ok: 'true',
  encontrado: 'true',
  phone,
  user_id: u.user_id,
  nombre: u.name || '',
  cedula: u.document_id || 'No registrada',
  agente: u.agent_name || '',
  registrado: u.registered ? 'true' : 'false',
  total_goles: String(u.total_goals || 0),
  status: u.status
}}];
